// lastConfigMatches returns true if the provided source file and/or adapter
// matches the recorded last-config. Matching rules (in priority order):
// 1. If srcAdapter is provided and differs from the recorded adapter, no match.
// 2. If srcFile exactly equals the recorded file, match.
// 3. If both sides can be made absolute and equal, match.
// 4. If basenames are equal, match.
func lastConfigMatches(srcFile, srcAdapter string) bool {
	lf, la, _ := getLastConfig()

	// If adapter is provided, it must match.
	if srcAdapter != "" && srcAdapter != la {
		return false
	}

	// Quick equality check.
	if srcFile == lf {
		return true
	}

	// Try absolute path comparison.
	sAbs, sErr := filepath.Abs(srcFile)
	lAbs, lErr := filepath.Abs(lf)
	if sErr == nil && lErr == nil && sAbs == lAbs {
		return true
	}

	// Final fallback: basename equality.
	if filepath.Base(srcFile) == filepath.Base(lf) {
		return true
	}

	return false
}

func checkKeyInterval(
	lg *zap.Logger,
	cachedPerms *unifiedRangePermissions,
	key, rangeEnd []byte,
	permtyp authpb.Permission_Type,
) bool {
	if isOpenEnded(rangeEnd) {
		rangeEnd = nil
		// nil rangeEnd will be converetd to []byte{}, the largest element of BytesAffineComparable,
		// in NewBytesAffineInterval().
	}

	ivl := adt.NewBytesAffineInterval(key, rangeEnd)
	switch permtyp {
	case authpb.Permission_READ:
		return cachedPerms.readPerms.Contains(ivl)
	case authpb.Permission_WRITE:
		return cachedPerms.writePerms.Contains(ivl)
	default:
		lg.Panic("unknown auth type", zap.String("auth-type", permtyp.String()))
	}
	return false
}

func checkKeyPoint(lg *zap.Logger, cachedPerms *unifiedRangePermissions, key []byte, permtyp authpb.Permission_Type) bool {
	pt := adt.NewBytesAffinePoint(key)
	switch permtyp {
	case authpb.Permission_READ:
		return cachedPerms.readPerms.Intersects(pt)
	case authpb.Permission_WRITE:
		return cachedPerms.writePerms.Intersects(pt)
	default:
		lg.Panic("unknown auth type", zap.String("auth-type", permtyp.String()))
	}
	return false
}

func unaryRetryInterceptor(cfg retryConfig) grpc.UnaryClientInterceptor {
	return grpc_retry.UnaryClientInterceptor(
		grpc_retry.WithMax(cfg.Max),
		grpc_retry.WithBackoff(grpc_retry.BackoffExponentialWithJitter(
			cfg.Backoff, cfg.BackoffJitter)),
		grpc_retry.WithCodes(codes.ResourceExhausted, codes.Unavailable, codes.Aborted),
	)
}

func unaryRetryInstrument(metric *prometheus.CounterVec) grpc.UnaryClientInterceptor {
	return func(ctx context.Context, method string, req, resp interface{},
		cc *grpc.ClientConn, invoker grpc.UnaryInvoker, opts ...grpc.CallOption) error {
		attempt, err := strconv.Atoi(
			metautils.ExtractOutgoing(ctx).Get(grpc_retry.AttemptMetadataKey))
		if err == nil && attempt > 0 {
			metric.WithLabelValues(method).Inc()
		}
		return invoker(ctx, method, req, resp, cc, opts...)
	}
}

func connectionBackoffOptions() grpc.DialOption {
	return grpc.WithConnectParams(grpc.ConnectParams{
